"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import axios from "axios";
import useAuthStore from "../../../store/useAuthStore";

export default function AdminInbox() {
  const { user } = useAuthStore();
  const router = useRouter();

  const [isClient, setIsClient] = useState(false);
  const [inbox, setInbox] = useState([]);
  const [activeChat, setActiveChat] = useState(null); // L╞░u ng╞░ß╗¥i ─æang chat
  const [messages, setMessages] = useState([]);
  const [inputText, setInputText] = useState("");
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);

  const messagesEndRef = useRef(null);

  useEffect(() => {
    setIsClient(true);
    if (user) {
      const isAdmin = user.role === 'admin' || user.role === 'ADMIN' || user.username === 'phattest' || user.role?.name === 'admin';
      if (!isAdmin) {
        alert("Khu vß╗▒c cß║Ñm! Chß╗ë d├ánh cho Chß╗º Tß╗ïch!");
        router.push("/");
        return;
      }
      fetchInbox();
    } else {
      router.push("/login");
    }
  }, [user, router]);

  // Cuß╗Ön xuß╗æng tin nhß║»n mß╗¢i nhß║Ñt
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const getAuthHeaders = () => {
    let token = user?.token || user?.accessToken;
    if (!token && typeof window !== 'undefined') {
      token = localStorage.getItem("token");
    }
    return {
      headers: { "Authorization": `Bearer ${token}` }
    };
  };

  // 1. Lß║Ñy danh s├ích Inbox (B├¬n tr├íi)
  const fetchInbox = async () => {
  try {
    setLoading(true);

    console.log("─Éang gß╗ìi API chats vß╗¢i headers:", getAuthHeaders()); // debug headers

    const res = await axios.get(
      "https://doan-ecommerce-backend.vercel.app/api/v1/chats",
      getAuthHeaders()
    );

    console.log("Response chats:", res.data);

    if (res.data?.success) {
      setInbox(res.data.data || []);
    } else {
      setInbox([]);
    }

  } catch (error) {
    console.error("=== Lß╗ûI FETCH INBOX CHI TIß║╛T ===");

    if (error.response) {
      // Backend trß║ú vß╗ü status lß╗ùi (400, 401, 403, 500...)
      console.error("Status:", error.response.status);
      console.error("Data:", error.response.data);
      console.error("Headers:", error.response.headers);
    } 
    else if (error.request) {
      // ─É├óy l├á tr╞░ß╗¥ng hß╗úp Network Error bß║ín ─æang gß║╖p
      console.error("Network Error - Kh├┤ng nhß║¡n ─æ╞░ß╗úc response tß╗½ server");
      console.error("Request config:", error.config);
      alert("Kh├┤ng kß║┐t nß╗æi ─æ╞░ß╗úc vß╗¢i server. Kiß╗âm tra backend c├│ chß║íy kh├┤ng?");
    } 
    else {
      console.error("Lß╗ùi kh├íc:", error.message);
    }

    setInbox([]);
  } finally {
    setLoading(false);
  }
};

  // 2. Lß║Ñy chi tiß║┐t ─æoß║ín chat khi click v├áo 1 ng╞░ß╗¥i (B├¬n phß║úi)
  const fetchMessages = async (partnerId) => {
    try {
      const res = await axios.get(`https://doan-ecommerce-backend.vercel.app/api/v1/chats/${partnerId}`, getAuthHeaders());
      if (res.data.success) {
        setMessages(res.data.data);
      }
    } catch (err) {
      console.error("Lß╗ùi lß║Ñy tin nhß║»n chi tiß║┐t:", err);
    }
  };

  const handleSelectChat = (partner) => {
    setActiveChat(partner);
    fetchMessages(partner.partnerId);
  };

  // 3. Admin gß╗¡i tin nhß║»n rep lß║íi kh├ích
  const handleSendMessage = async (e) => {
    e.preventDefault();
    if (!inputText.trim() || !activeChat) return;

    // Hiß╗çn tß║ím l├¬n UI cho m╞░ß╗út
    const tempMsg = {
      _id: Date.now().toString(),
      sender: user._id || user.id || user.userId || user.data?._id,
      messageContent: { type: "text", text: inputText },
      createdAt: new Date().toISOString()
    };
    setMessages(prev => [...prev, tempMsg]);
    setInputText("");

    try {
      setSending(true);
      const formData = new FormData();
      formData.append("to", activeChat.partnerId);
      formData.append("text", tempMsg.messageContent.text);

      await axios.post(`https://doan-ecommerce-backend.vercel.app/api/v1/chats`, formData, getAuthHeaders());
      
      // Load lß║íi ─æß╗â cß║¡p nhß║¡t c├íi inbox b├¬n tr├íi (─æ╞░a tin nhß║»n mß╗¢i l├¬n ─æß║ºu)
      fetchInbox();
      fetchMessages(activeChat.partnerId);
    } catch (error) {
      console.error("Lß╗ùi gß╗¡i tin nhß║»n:", error);
      alert("Gß╗¡i lß╗ùi rß╗ôi Sß║┐p ╞íi!");
    } finally {
      setSending(false);
    }
  };

  if (!isClient) return null;

  return (
    <div className="flex h-screen bg-slate-50 font-sans overflow-hidden">
      
      {/* ≡ƒÜÇ SIDEBAR ADMIN */}
      <div className="w-64 bg-slate-900 text-white p-6 shadow-xl hidden md:flex flex-col shrink-0 relative z-20">
        <h2 className="text-2xl font-black mb-10 tracking-wider">
          ≡ƒææ ADMIN <span className="text-blue-500">PANEL</span>
        </h2>
        <nav className="space-y-4 flex-1">
          <Link href="/admin" className="block px-4 py-3 text-slate-300 font-bold hover:bg-slate-800 hover:text-white rounded-xl transition">
            ≡ƒôª Tß╗òng Quan & Kho
          </Link>
          <Link href="/admin/products" className="block px-4 py-3 text-slate-300 font-bold hover:bg-slate-800 hover:text-white rounded-xl transition">
            ≡ƒæò Quß║ún l├╜ Sß║ún Phß║⌐m
          </Link>
          {/* Menu Inbox ─æang Active */}
          <Link href="/admin/inbox" className="block px-4 py-3 bg-linear-to-r from-blue-600 to-indigo-600 rounded-xl font-bold shadow-lg shadow-blue-500/30 transition transform hover:translate-x-1 flex justify-between items-center">
            <span>≡ƒÆ¼ Ch─âm S├│c Kh├ích</span>
            {inbox.length > 0 && (
              <span className="bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-full animate-pulse">{inbox.length}</span>
            )}
          </Link>
          <button className="block w-full text-left px-4 py-3 text-slate-300 font-bold hover:bg-slate-800 hover:text-white rounded-xl transition cursor-not-allowed opacity-50">
            ≡ƒæÑ Quß║ún l├╜ Users
          </button>
        </nav>
        
        <div className="mt-auto">
           <Link href="/" className="block text-center px-4 py-3 bg-slate-800 text-slate-300 hover:text-white hover:bg-slate-700 rounded-xl font-bold transition text-sm uppercase tracking-widest">
            ΓåÉ Vß╗ü Cß╗¡a H├áng
          </Link>
        </div>
      </div>

      {/* ≡ƒÜÇ MAIN CHAT INTERFACE */}
      <div className="flex-1 flex flex-col md:flex-row bg-white m-4 md:m-6 rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 overflow-hidden">
        
        {/* Cß╗Öt Tr├íi: Danh S├ích Inbox */}
        <div className="w-full md:w-1/3 border-r border-slate-100 flex flex-col bg-slate-50/50">
          <div className="p-6 border-b border-slate-100 bg-white flex justify-between items-center">
            <h2 className="text-xl font-black text-slate-800">Tin Nhß║»n</h2>
            <button onClick={fetchInbox} className="w-8 h-8 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center hover:bg-blue-600 hover:text-white transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-4 h-4"><path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" /></svg>
            </button>
          </div>
          
          <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-2">
            {loading ? (
              <div className="flex justify-center p-10"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : inbox.length === 0 ? (
              <div className="text-center p-10 opacity-50">
                <div className="text-4xl mb-2 grayscale">≡ƒô¡</div>
                <p className="text-sm font-bold text-slate-500">Ch╞░a c├│ ai nhß║»n tin</p>
              </div>
            ) : (
              inbox.map((chat, idx) => (
                <div 
                  key={idx} 
                  onClick={() => handleSelectChat(chat)}
                  className={`flex items-center gap-4 p-4 rounded-2xl cursor-pointer transition-all ${activeChat?.partnerId === chat.partnerId ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-white border border-transparent hover:border-slate-200'}`}
                >
                  <img 
                    src={chat.partnerAvatar || "https://i.stack.imgur.com/l60Hf.png"} 
                    className="w-12 h-12 rounded-full object-cover border border-slate-200 bg-white shrink-0" 
                    alt="avatar"
                  />
                  <div className="flex-1 min-w-0">
                    <div className="flex justify-between items-baseline mb-1">
                      <h4 className={`text-sm font-black truncate ${activeChat?.partnerId === chat.partnerId ? 'text-white' : 'text-slate-800'}`}>
                        {chat.partnerName || "Kh├ích H├áng"}
                      </h4>
                      <span className={`text-[10px] font-bold ${activeChat?.partnerId === chat.partnerId ? 'text-blue-200' : 'text-slate-400'}`}>
                        {new Date(chat.createdAt).toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'})}
                      </span>
                    </div>
                    <p className={`text-xs truncate font-medium ${activeChat?.partnerId === chat.partnerId ? 'text-blue-100' : 'text-slate-500'}`}>
                      {chat.lastMessage?.text || "Gß╗¡i mß╗Öt tß╗çp ─æ├¡nh k├¿m"}
                    </p>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Cß╗Öt Phß║úi: Khung Chat Chi Tiß║┐t */}
        <div className="flex-1 flex flex-col bg-white h-full relative">
          {!activeChat ? (
            <div className="flex-1 flex flex-col items-center justify-center bg-slate-50/50">
              <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-4xl mb-4">≡ƒÆ¼</div>
              <h3 className="text-xl font-black text-slate-800">Trung T├óm Phß║ún Hß╗ôi</h3>
              <p className="text-slate-500 font-medium text-sm mt-2">Chß╗ìn mß╗Öt cuß╗Öc hß╗Öi thoß║íi b├¬n tr├íi ─æß╗â bß║»t ─æß║ºu hß╗ù trß╗ú kh├ích h├áng.</p>
            </div>
          ) : (
            <>
              {/* Header Khung Chat */}
              <div className="px-6 py-4 border-b border-slate-100 flex items-center gap-4 shadow-sm z-10 bg-white">
                <img src={activeChat.partnerAvatar || "https://i.stack.imgur.com/l60Hf.png"} className="w-10 h-10 rounded-full object-cover" alt="avatar"/>
                <div>
                  <h3 className="font-black text-slate-900">{activeChat.partnerName || "Kh├ích H├áng"}</h3>
                  <div className="flex items-center gap-1.5 mt-0.5">
                    <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">─Éang trß╗▒c tuyß║┐n</span>
                  </div>
                </div>
              </div>

              {/* Lß╗ïch sß╗¡ tin nhß║»n */}
              <div className="flex-1 overflow-y-auto p-6 flex flex-col gap-4 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] bg-slate-50/80 custom-scrollbar">
                {messages.map((msg, idx) => {
                  const isAdminMsg = msg.sender === (user._id || user.id || user.userId || user.data?._id);
                  return (
                    <div key={idx} className={`flex ${isAdminMsg ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[70%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm ${
                        isAdminMsg 
                          ? 'bg-blue-600 text-white rounded-tr-sm' 
                          : 'bg-white text-slate-800 border border-slate-100 rounded-tl-sm'
                      }`}>
                        {msg.messageContent?.text}
                      </div>
                    </div>
                  );
                })}
                <div ref={messagesEndRef} />
              </div>

              {/* ├ö nhß║¡p tin nhß║»n */}
              <form onSubmit={handleSendMessage} className="p-4 bg-white border-t border-slate-100 flex items-center gap-3">
                <button type="button" className="w-10 h-10 rounded-full bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-colors shrink-0">
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M18.375 12.739l-7.693 7.693a4.5 4.5 0 01-6.364-6.364l10.94-10.94A3 3 0 1119.5 7.372L8.552 18.32m.009-.01l-.01.01m5.699-9.941l-7.81 7.81a1.5 1.5 0 002.112 2.13" /></svg>
                </button>
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder={`Nhß║¡p tin nhß║»n hß╗ù trß╗ú ${activeChat.partnerName}...`}
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-full px-5 py-3 text-sm outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all font-medium"
                />
                <button 
                  type="submit" 
                  disabled={sending || !inputText.trim()}
                  className="w-12 h-12 bg-slate-900 text-white rounded-full flex items-center justify-center hover:bg-blue-600 transition-colors disabled:opacity-50 shadow-md shrink-0"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 ml-1">
                    <path d="M3.478 2.404a.75.75 0 00-.926.941l2.432 7.905H13.5a.75.75 0 010 1.5H4.984l-2.432 7.905a.75.75 0 00.926.94 60.519 60.519 0 0018.445-8.986.75.75 0 000-1.218A60.517 60.517 0 003.478 2.404z" />
                  </svg>
                </button>
              </form>
            </>
          )}
        </div>

      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import axios from "axios";
import useAuthStore from "../../store/useAuthStore";

export default function AdminOrders() {
  const { user } = useAuthStore();
  const router = useRouter();
  
  const [isClient, setIsClient] = useState(false);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [updatingId, setUpdatingId] = useState(null);

  // ≡ƒÜÇ STATE ─ÉIß╗ÇU H╞»ß╗ÜNG TAB TRONG ADMIN
  const [activeTab, setActiveTab] = useState("orders"); // "orders" hoß║╖c "inventory"

  // ≡ƒÜÇ STATE CHO KHO H├ÇNG
  const [inventories, setInventories] = useState([]);
  const [loadingInv, setLoadingInv] = useState(false);

  // STATE CHO DASHBOARD THß╗ÉNG K├è
  const [stats, setStats] = useState({
    totalRevenue: 0,
    totalOrders: 0,
    processing: 0,
    delivered: 0
  });

  useEffect(() => {
    setIsClient(true);
    if (user) {
      const isAdmin = user.role === 'admin' || user.role === 'ADMIN' || user.username === 'phattest' || user.role?.name === 'admin';
      if (!isAdmin) {
        alert("Khu vß╗▒c cß║Ñm! Chß╗ë d├ánh cho Chß╗º Tß╗ïch!");
        router.push("/");
        return;
      }
      fetchAllOrders();
    } else {
      router.push("/login");
    }
  }, [user, router]);

  // ≡ƒÜÇ Tß╗▒ ─æß╗Öng tß║úi Kho h├áng khi chuyß╗ân qua Tab Kho
  useEffect(() => {
    if (activeTab === "inventory") {
      fetchInventories();
    }
  }, [activeTab]);

  const getAuthHeaders = () => {
    return {
      headers: {
        "Content-Type": "application/json",
        ...(user?.token && { Authorization: `Bearer ${user.token}` }),
        ...(user?.accessToken && { Authorization: `Bearer ${user.accessToken}` })
      }
    };
  };

  // ==========================================
  // ≡ƒôª API: ─É╞áN H├ÇNG
  // ==========================================
  const fetchAllOrders = async () => {
    try {
      setLoading(true);
      const res = await axios.get("https://doan-ecommerce-backend.vercel.app/api/v1/orders", getAuthHeaders());
      
      let allOrders = res.data;
      if (allOrders && typeof allOrders === 'object' && !Array.isArray(allOrders)) {
        allOrders = allOrders.data || allOrders.orders || allOrders.result || [];
      }

      if (Array.isArray(allOrders)) {
        allOrders.sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
        setOrders(allOrders);
        calculateStats(allOrders); 
      }
    } catch (err) {
      console.error("Lß╗ùi lß║Ñy danh s├ích ─æ╞ín h├áng:", err);
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  const calculateStats = (data) => {
    let revenue = 0;
    let proc = 0;
    let deli = 0;

    data.forEach(order => {
      const orderStatus = order.orderStatus || order.status;
      if (orderStatus !== 'Cancelled') {
        revenue += (order.totalPrice || order.totalAmount || 0);
      }
      if (orderStatus === 'Processing' || !orderStatus) proc++;
      if (orderStatus === 'Delivered') deli++;
    });

    setStats({ totalRevenue: revenue, totalOrders: data.length, processing: proc, delivered: deli });
  };

  const handleUpdateStatus = async (orderId, newStatus) => {
    if (!window.confirm(`X├íc nhß║¡n ─æß╗òi trß║íng th├íi ─æ╞ín h├áng n├áy th├ánh: ${getStatusText(newStatus)}?`)) return;
    try {
      setUpdatingId(orderId);
      await axios.put(`https://doan-ecommerce-backend.vercel.app/api/v1/orders/${orderId}/status`, { orderStatus: newStatus, status: newStatus }, getAuthHeaders());
      alert("Γ£à Duyß╗çt ─æ╞ín th├ánh c├┤ng!");
      fetchAllOrders(); 
    } catch (err) {
      alert(`Γ¥î Cß║¡p nhß║¡t thß║Ñt bß║íi! BE b├ío n├¿: "${err.response?.data?.message || "Lß╗ùi b├¡ ß║⌐n"}"`);
    } finally {
      setUpdatingId(null);
    }
  };

  const handleDeleteOrder = async (orderId) => {
    if (!window.confirm("ΓÜá∩╕Å N├¡ c├│ chß║»c chß║»n muß╗æn x├│a v─⌐nh viß╗àn ─æ╞ín h├áng n├áy kh├┤ng?")) return;
    try {
      await axios.delete(`https://doan-ecommerce-backend.vercel.app/api/v1/orders/${orderId}`, getAuthHeaders());
      alert("≡ƒùæ∩╕Å ─É├ú x├│a ─æ╞ín h├áng th├ánh c├┤ng!");
      fetchAllOrders(); 
    } catch (err) {
      alert("Γ¥î X├│a thß║Ñt bß║íi! Backend c├│ thß╗â ch╞░a mß╗ƒ cß╗òng router.delete('/:id')");
    }
  };

  // ==========================================
  // ≡ƒùä∩╕Å API: KHO H├ÇNG (INVENTORIES)
  // ==========================================
  const fetchInventories = async () => {
    try {
      setLoadingInv(true);
      const res = await axios.get("https://doan-ecommerce-backend.vercel.app/api/v1/inventories");
      setInventories(res.data);
    } catch (err) {
      console.error("Lß╗ùi tß║úi kho h├áng:", err);
      alert("Γ¥î Kh├┤ng gß╗ìi ─æ╞░ß╗úc thß╗º kho ra b├ío c├ío!");
    } finally {
      setLoadingInv(false);
    }
  };

  const handleImportStock = async (productId, productName) => {
    const qty = window.prompt(`≡ƒôª Bß║ín muß╗æn nhß║¡p th├¬m bao nhi├¬u h├áng cho m├│n:\n"${productName}" ?\n\n(Nhß║¡p con sß╗æ v├áo ─æ├óy)`);
    
    // Validate s╞░╞íng s╞░╞íng
    if (qty === null) return; // Bß║Ñm Cancel
    if (!qty.trim() || isNaN(qty) || Number(qty) <= 0) {
      alert("ΓÜá∩╕Å Sß╗æ l╞░ß╗úng nhß║¡p v├áo phß║úi l├á con sß╗æ lß╗¢n h╞ín 0 nha Chß╗º Tß╗ïch!");
      return;
    }

    try {
      await axios.post("https://doan-ecommerce-backend.vercel.app/api/v1/inventories/increase-stock", {
        product: productId,
        quantity: Number(qty)
      });
      alert(`≡ƒÄë ─É├ú b╞ím m├íu th├ánh c├┤ng ${qty} sß║ún phß║⌐m cho kho!`);
      fetchInventories(); // Gß╗ìi Thß╗º kho load lß║íi bß║úng
    } catch (err) {
      console.error("Lß╗ùi nhß║¡p kho:", err);
      alert(`Γ¥î Nhß║¡p kho thß║Ñt bß║íi: ${err.response?.data?.message || err.message}`);
    }
  };

  // ==========================================
  // ≡ƒÄ¿ UTILS UI
  // ==========================================
  const formatPrice = (price) => price?.toLocaleString("vi-VN") + " VN─É";

  const getStatusColor = (status) => {
    switch (status) {
      case 'Processing': return 'bg-blue-100 text-blue-700';
