"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import axios from "axios";
import useCartStore from "../../store/useCartStore"; // ─Éß║úm bß║úo ─æ╞░ß╗¥ng dß║½n ─æ├║ng tß╗¢i kho Zustand
import Footer from "../../components/Footer";

export default function CartPage() {
  const router = useRouter();
  
  // Lß║Ñy dß╗» liß╗çu tß╗½ kho Giß╗Å H├áng
  // Giß║ú sß╗¡ kho cß╗ºa ├┤ng c├│ cart (mß║úng data) v├á removeFromCart (h├ám x├│a)
  const { cart, removeFromCart } = useCartStore();

  // ≡ƒÜÇ STATE CHO VOUCHER (M├â GIß║óM GI├ü)
  const [voucherCode, setVoucherCode] = useState("");
  const [discountPercent, setDiscountPercent] = useState(0);
  const [isApplying, setIsApplying] = useState(false);
  const [voucherMessage, setVoucherMessage] = useState({ type: "", text: "" });

  // 1. Gß╗Öp c├íc sß║ún phß║⌐m tr├╣ng ID lß║íi ─æß╗â hiß╗ân thß╗ï Sß╗æ l╞░ß╗úng cho ─æß║╣p (nß║┐u kho cß╗ºa ├┤ng l╞░u dß║íng mß║úng phß║│ng)
  const groupedCart = cart.reduce((acc, item) => {
    const existing = acc.find(i => i._id === item._id);
    if (existing) {
      existing.quantity = (existing.quantity || 1) + 1;
    } else {
      acc.push({ ...item, quantity: item.quantity || 1 });
    }
    return acc;
  }, []);

  // 2. T├¡nh to├ín tiß╗ün nong
  const subTotal = groupedCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const discountAmount = (subTotal * discountPercent) / 100;
  const finalTotal = subTotal - discountAmount;

  const formatPrice = (price) => Math.round(price).toLocaleString('vi-VN') + " VN─É";

  // ≡ƒÜÇ 3. H├ÇM ├üP Dß╗ñNG VOUCHER Gß╗îI XUß╗ÉNG BACKEND
  const handleApplyVoucher = async () => {
    if (!voucherCode.trim()) {
      setVoucherMessage({ type: "error", text: "N├¡ ch╞░a nhß║¡p m├ú m├á ─æ├▓i giß║úm gi├í sao?" });
      return;
    }

    try {
      setIsApplying(true);
      setVoucherMessage({ type: "", text: "" });

      const res = await axios.post("https://doan-ecommerce-backend.vercel.app/api/v1/vouchers/apply", {
        code: voucherCode
      });

      if (res.data.success) {
        setDiscountPercent(res.data.discountPercent);
        setVoucherMessage({ type: "success", text: `≡ƒÄë B├║ ngay m├ú giß║úm ${res.data.discountPercent}% Chß╗º Tß╗ïch ╞íi!` });
      }
    } catch (err) {
      setDiscountPercent(0);
      const errorMsg = err.response?.data?.message || "M├ú n├áy dß╗Åm hoß║╖c bß╗ï lß╗ùi rß╗ôi!";
      setVoucherMessage({ type: "error", text: `Γ¥î ${errorMsg}` });
    } finally {
      setIsApplying(false);
    }
  };

  // 4. X├│a Voucher
  const handleRemoveVoucher = () => {
    setVoucherCode("");
    setDiscountPercent(0);
    setVoucherMessage({ type: "", text: "" });
  };

  // 5. Chuyß╗ân sang trang Thanh To├ín (Truyß╗ün lu├┤n sß╗æ tiß╗ün ─æ├ú giß║úm qua URL hoß║╖c State)
  const handleCheckout = () => {
    // Nß║┐u c├│ trang checkout ri├¬ng th├¼ push qua, kß║╣p theo phß║ºn tr─âm giß║úm gi├í ─æß╗â b├¬n kia t├¡nh
    router.push(`/checkout?discount=${discountPercent}`);
