  const handleIncrease = () => {
    if (stock !== null && quantity >= stock) {
      alert(`Kho chß╗ë c├▓n ─æ├║ng ${stock} c├íi th├┤i Chß╗º Tß╗ïch ╞íi! Kh├ích th├┤ng cß║úm nhen!`);
