    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import axios from "axios";
import useCartStore from "../../store/useCartStore";
import Footer from "../../components/Footer";

export default function ProductsPage() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // L├┤i chi├¬u th├¬m v├áo giß╗Å h├áng ra x├ái
  const { addToCart } = useCartStore();

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const res = await axios.get("https://doan-ecommerce-backend.vercel.app/api/v1/products?limit=50");
      
      // Bß║»t bß╗çnh cß║Ñu tr├║c data BE trß║ú vß╗ü
      let data = res.data;
      if (data && typeof data === 'object' && !Array.isArray(data)) {
        data = data.data || data.products || data.result || [];
      }

      if (Array.isArray(data)) {
        // ─Éß║úo ng╞░ß╗úc mß║úng ─æß╗â sß║ún phß║⌐m mß╗¢i ─æ─âng hiß╗çn l├¬n ─æß║ºu ti├¬n
        setProducts(data.reverse());
      }
    } catch (err) {
      console.error("Lß╗ùi lß║Ñy danh s├ích sß║ún phß║⌐m:", err);
      setProducts([]);
    } finally {
      setLoading(false);
    }
  };

  const formatPrice = (price) => price?.toLocaleString("vi-VN") + " VN─É";

