"use client";
import { useState, useEffect } from "react";
import axios from "axios";
import Link from "next/link";
// ─É├ú fix cß╗⌐ng chuß║⌐n ─æ╞░ß╗¥ng dß║½n
import useAuthStore from "../../../store/useAuthStore"; 

export default function MyReservations() {
  const { user } = useAuthStore();
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMyReservations();
  }, [user]);

  const fetchMyReservations = async () => {
    try {
      setLoading(true);
      
      // ≡ƒÜÇ THUß║¼T TO├üN TRUY T├îM ID TUYß╗åT ─Éß╗ÉI
      let currentUser = user;
      let currentToken = user?.token || (typeof window !== "undefined" ? localStorage.getItem("token") : "");

      // 1. M├▓ trong LocalStorage nß║┐u state bß╗ï rß╗ùng
      if (!currentUser || (!currentUser._id && !currentUser.id)) {
        for (let i = 0; i < localStorage.length; i++) {
          const key = localStorage.key(i);
          try {
            const item = JSON.parse(localStorage.getItem(key));
            if (item?.state?.user) currentUser = item.state.user;
            if (item?.state?.token) currentToken = item.state.token;
          } catch (error) {}
        }
      }

      let userId = currentUser?._id || currentUser?.id || currentUser?.userId || currentUser?.data?._id;

      // 2. Kß║╣t qu├í th├¼ giß║úi m├ú lu├┤n Token (Hack mode)
      if (!userId && currentToken) {
        try {
          const payload = JSON.parse(atob(currentToken.split('.')[1]));
          userId = payload._id || payload.id || payload.userId;
        } catch (error) {}
      }

      // 3. Nß║┐u vß║½n kh├┤ng ra th├¼ ─æ├ánh chß╗ïu
      if (!userId) {
        console.log("─Éang chß╗¥ tß║úi th├┤ng tin Chß╗º Tß╗ïch...");
        setLoading(false);
        return;
      }

      // ─É├â C├ô ID -> Gß╗îI API Lß║ñY ─É╞áN H├ÇNG
      const res = await axios.get(`https://doan-ecommerce-backend.vercel.app/api/v1/reservations/user/${userId}`);
      
      // Sß║»p xß║┐p ─æ╞ín mß╗¢i nhß║Ñt l├¬n ─æß║ºu
      let data = res.data.data || [];
      data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
      
      setReservations(data);
    } catch (error) {
      console.error("Lß╗ùi tß║úi danh s├ích:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async (id) => {
    if(confirm("Chß║»c chß║»n muß╗æn hß╗ºy giß╗» m├│n n├áy kh├┤ng n├¡? Hß╗ºy xong l├á ng╞░ß╗¥i kh├íc mua mß║Ñt r├íng chß╗ïu nha!")) {
      try {
        await axios.put(`https://doan-ecommerce-backend.vercel.app/api/v1/reservations/${id}/cancel`);
        alert("Γ£à ─É├ú nhß║ú h├áng th├ánh c├┤ng!");
        fetchMyReservations(); // Tß║úi lß║íi danh s├ích ngay lß║¡p tß╗⌐c
      } catch (err) {
        alert("Γ¥î Hß╗ºy thß║Ñt bß║íi, thß╗¡ lß║íi sau nha Sß║┐p!");
      }
    }
  };

  const formatPrice = (price) => price?.toLocaleString("vi-VN") + " VN─É";

  return (
    <div className="min-h-screen bg-slate-50 py-12 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-4xl mx-auto">
        
