                    <img 
                      src={item.product?.image || (item.product?.images && item.product.images[0]) || "https://via.placeholder.com/150"} 
                      alt={item.product?.title || item.product?.name} 
                      className={`w-20 h-20 object-contain mix-blend-multiply bg-slate-50 rounded-xl p-2 border border-slate-100 shrink-0 ${isCancelled ? 'grayscale opacity-50' : ''}`} 
                    />
                    <div>
                      <h3 className={`font-black text-lg line-clamp-1 ${isCancelled ? 'text-slate-400 line-through' : 'text-slate-900'}`}>
                        {item.product?.title || item.product?.name || "Sß║ún phß║⌐m ─æ├ú bß╗ï x├│a"}
                      </h3>
                      <div className="flex flex-wrap items-center gap-3 mt-2 text-sm">
                        <span className="font-bold text-slate-500">SL: <span className="text-slate-900">{item.quantity}</span></span>
                        <span className="text-slate-300">|</span>
                        <span className="font-black text-blue-600">{formatPrice(item.product?.price)}</span>
                      </div>
                      <div className="text-[10px] text-slate-400 font-bold mt-1">
                        Ng├áy ─æß║╖t: {new Date(item.createdAt).toLocaleString('vi-VN')}
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center justify-between w-full md:w-auto gap-4 border-t md:border-t-0 border-slate-100 pt-4 md:pt-0">
                    <span className={`text-xs px-3 py-1.5 rounded-lg font-black uppercase tracking-widest ${
                      isPending ? 'bg-orange-100 text-orange-600 border border-orange-200' : 
                      isCancelled ? 'bg-red-100 text-red-600 border border-red-200' : 
                      'bg-green-100 text-green-600 border border-green-200'
                    }`}>
                      {isPending ? '─ÉANG GIß╗« H├ÇNG' : isCancelled ? '─É├â Hß╗ªY' : item.status}
                    </span>
                    
                    {isPending && (
                      <button 
                        onClick={() => handleCancel(item._id)} 
                        className="px-5 py-2.5 bg-white border-2 border-slate-200 text-slate-600 rounded-xl hover:border-red-500 hover:text-red-500 hover:bg-red-50 font-black uppercase tracking-widest text-xs transition-colors"
                      >
                        Hß╗ºy Giß╗»
                      </button>
                    )}
                  </div>

                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import axios from "axios";
import useAuthStore from "../store/useAuthStore";
import Link from "next/link";

export default function ChatBubble() {
  const { user } = useAuthStore();
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputText, setInputText] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  // ΓÜá∩╕Å QUAN TRß╗îNG: Thay ID n├áy bß║▒ng _id cß╗ºa t├ái khoß║ún Admin trong Database cß╗ºa n├¡
  const ADMIN_ID = "69c76c973aee4e3f42467437"; // <--- Sß╗¼A CHß╗û N├ÇY NHA CHß╗ª Tß╗èCH

  // Cuß╗Ön xuß╗æng cuß╗æi mß╗ùi khi c├│ tin nhß║»n mß╗¢i
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) {
      scrollToBottom();
    }
  }, [messages, isOpen]);

  // Lß║Ñy lß╗ïch sß╗¡ chat khi mß╗ƒ bong b├│ng
  useEffect(() => {
    if (isOpen && user) {
      fetchMessages();
      // T├╣y chß╗ìn: C├ái mß╗Öt c├íi ─æß╗ông hß╗ô (interval) gß╗ìi API 5s/lß║ºn ─æß╗â check tin nhß║»n mß╗¢i (Polling)
      const interval = setInterval(fetchMessages, 5000);
      return () => clearInterval(interval);
    }
  }, [isOpen, user]);

  const getAuthHeaders = () => {
    let token = user?.token || user?.accessToken;
    if (!token && typeof window !== 'undefined') {
      token = localStorage.getItem("token");
    }
    return {
      headers: {
        "Authorization": `Bearer ${token}`
      }
    };
  };

  const fetchMessages = async () => {
    try {
      const res = await axios.get(`https://doan-ecommerce-backend.vercel.app/api/v1/chats/${ADMIN_ID}`, getAuthHeaders());
      if (res.data.success) {
        // ─Éß║úm bß║úo dß╗» liß╗çu lu├┤n l├á mß║úng ─æß╗â tr├ính lß╗ùi .map() l├ám sß║¡p web
        setMessages(res.data.data || []);
      }
    } catch (error) {
      console.error("Lß╗ùi tß║úi tin nhß║»n:", error);
    }
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    // Hiß╗ân thß╗ï tin nhß║»n tß║ím thß╗¥i l├¬n UI tr╞░ß╗¢c cho m╞░ß╗út (Optimistic UI)
    const tempMsg = {
      _id: Date.now().toString(),
      sender: user._id || user.id || user.userId || user.data?._id,
      messageContent: { type: "text", text: inputText },
      createdAt: new Date().toISOString()
    };
    setMessages(prev => [...prev, tempMsg]);
    setInputText("");

    try {
      setLoading(true);
      // Gß╗¡i ─æi theo chuß║⌐n form-data v├¼ BE n├úy m├¼nh hß╗ù trß╗ú uploadImage
      const formData = new FormData();
      formData.append("to", ADMIN_ID);
      formData.append("text", tempMsg.messageContent.text);

      await axios.post(`https://doan-ecommerce-backend.vercel.app/api/v1/chats`, formData, getAuthHeaders());

      // Gß╗¡i xong gß╗ìi lß║íi danh s├ích cho chß║»c
      fetchMessages();
    } catch (error) {
      console.error("Lß╗ùi gß╗¡i tin nhß║»n:", error);
      alert("Gß╗¡i lß╗ùi rß╗ôi n├¡ ╞íi!");
    } finally {
      setLoading(false);
    }
  };

  // Nß║┐u l├á admin th├¼ kh├┤ng hiß╗çn bong b├│ng n├áy (Admin c├│ trang Inbox ri├¬ng)
  const isAdmin = user?.role === 'admin' || user?.role === 'ADMIN' || user?.username === 'phattest' || user?.role?.name === 'admin';
  if (isAdmin) return null;

  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      {/* Cß╗¡a sß╗ò Chat */}
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[350px] h-[450px] bg-white rounded-2xl shadow-[0_10px_40px_rgba(0,0,0,0.2)] border border-slate-100 flex flex-col overflow-hidden transition-all duration-300 transform origin-bottom-right">

          {/* Header */}
          <div className="bg-slate-900 text-white px-5 py-4 flex justify-between items-center shadow-md z-10">
            <div className="flex items-center gap-3">
              <div className="relative">
                <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-xl shadow-inner shadow-blue-400">≡ƒæ¿ΓÇì≡ƒÆ╝</div>
                <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-slate-900"></div>
              </div>
              <div>
                <h3 className="font-black text-sm tracking-wide">CSKH 2FAST.SHOP</h3>
                <p className="text-[10px] text-blue-200 font-bold tracking-widest uppercase">─Éang hoß║ít ─æß╗Öng</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-slate-300 hover:text-white transition-colors hover:rotate-90 duration-200">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* Body Chat */}
          <div className="flex-1 p-4 bg-slate-50 overflow-y-auto flex flex-col gap-3 custom-scrollbar">
            {!user ? (
              <div className="flex-1 flex flex-col items-center justify-center text-center px-4">
                <div className="text-5xl mb-3 grayscale opacity-40">≡ƒöÆ</div>
                <p className="text-sm font-bold text-slate-500 mb-4">N├¡ phß║úi ─æ─âng nhß║¡p mß╗¢i chat ─æ╞░ß╗úc vß╗¢i Shop nha!</p>
                <Link href="/login" className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-bold shadow-md hover:bg-slate-900 transition-colors text-xs uppercase tracking-widest">
                  ─É─âng nhß║¡p ngay
                </Link>
              </div>
            ) : messages.length === 0 ? (
              <div className="flex-1 flex flex-col items-center justify-center text-center opacity-50">
                <div className="text-4xl mb-2">≡ƒæï</div>
                <p className="text-xs font-bold text-slate-500">Ch╞░a c├│ tin nhß║»n n├áo. N├¡ hß╗Åi g├¼ ─æi!</p>
              </div>
            ) : (
              messages.map((msg, index) => {
                // X├íc ─æß╗ïnh tin nhß║»n l├á cß╗ºa m├¼nh (Kh├ích) hay cß╗ºa Shop (Admin)
                // ─Éß╗ü ph├▓ng msg.sender l├á object (do backend d├╣ng populate) thay v├¼ chuß╗ùi ID
                const senderId = msg.sender?._id || msg.sender;
                const isMine = senderId === (user._id || user.id || user.userId || user.data?._id);

                return (
                  <div key={msg._id || index} className={`flex ${isMine ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[75%] px-4 py-2.5 rounded-2xl text-sm font-medium leading-relaxed ${isMine
                        ? 'bg-blue-600 text-white rounded-tr-sm shadow-sm'
                        : 'bg-white text-slate-800 border border-slate-100 rounded-tl-sm shadow-sm'
                      }`}>
                      {msg.messageContent?.text}
                    </div>
                  </div>
                );
              })
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Khung Nhß║¡p Text */}
          {user && (
            <form onSubmit={handleSendMessage} className="p-3 bg-white border-t border-slate-100 flex items-center gap-2">
              <input
                type="text"
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                placeholder="Nhß║»n tin cho Shop..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-full px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              />
              <button
                type="submit"
                disabled={loading || !inputText.trim()}
                className="w-10 h-10 bg-slate-900 text-white rounded-full flex items-center justify-center hover:bg-blue-600 transition-colors disabled:opacity-50 shadow-md shrink-0"
              >
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 ml-1">
                  <path d="M3.478 2.404a.75.75 0 00-.926.941l2.432 7.905H13.5a.75.75 0 010 1.5H4.984l-2.432 7.905a.75.75 0 00.926.94 60.519 60.519 0 0018.445-8.986.75.75 0 000-1.218A60.517 60.517 0 003.478 2.404z" />
                </svg>
              </button>
            </form>
          )}
        </div>
      )}

      {/* N├║t Tr├▓n Mß╗ƒ Bong B├│ng */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-slate-900 text-white rounded-full shadow-[0_8px_30px_rgba(0,0,0,0.3)] flex items-center justify-center hover:scale-110 hover:bg-blue-600 transition-all duration-300 relative group"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-8 h-8">
            <path strokeLinecap="round" strokeLinejoin="round" d="M8.625 12a.375.375 0 11-.75 0 .375.375 0 01.75 0zm0 0H8.25m4.125 0a.375.375 0 11-.75 0 .375.375 0 01.75 0zm0 0H12m4.125 0a.375.375 0 11-.75 0 .375.375 0 01.75 0zm0 0h-.375M21 12c0 4.556-4.03 8.25-9 8.25a9.764 9.764 0 01-2.555-.337A5.972 5.972 0 015.41 20.97a5.969 5.969 0 01-.474-.065 4.48 4.48 0 00.978-2.025c.09-.457-.133-.901-.467-1.226C3.93 16.178 3 14.189 3 12c0-4.556 4.03-8.25 9-8.25s9 3.694 9 8.25z" />
          </svg>
          {/* Chß║Ñm ─æß╗Å th├┤ng b├ío */}
          <span className="absolute top-0 right-0 w-4 h-4 bg-red-500 rounded-full border-2 border-white animate-bounce"></span>
        </button>
      )}
    </div>
  );
}

